### LM Studio Configuration for MiniMax M2.1

Source: https://github.com/openclaw/openclaw/blob/main/docs/gateway/local-models.md

This configuration sets up OpenClaw to use the MiniMax M2.1 model served via LM Studio. It specifies the model alias, provider details including the base URL and API key, and model-specific parameters like context window and max tokens. It's designed for local LLM serving with OpenAI-compatible responses.

```json5
{
  "agents": {
    "defaults": {
      "model": { "primary": "lmstudio/minimax-m2.1-gs32" },
      "models": {
        "anthropic/claude-opus-4-5": { "alias": "Opus" },
        "lmstudio/minimax-m2.1-gs32": { "alias": "Minimax" }
      }
    }
  },
  "models": {
    "mode": "merge",
    "providers": {
      "lmstudio": {
        "baseUrl": "http://127.0.0.1:1234/v1",
        "apiKey": "lmstudio",
        "api": "openai-responses",
        "models": [
          {
            "id": "minimax-m2.1-gs32",
            "name": "MiniMax M2.1 GS32",
            "reasoning": false,
            "input": ["text"],
            "cost": { "input": 0, "output": 0, "cacheRead": 0, "cacheWrite": 0 },
            "contextWindow": 196608,
            "maxTokens": 8192
          }
        ]
      }
    }
  }
}
```

